import React from 'react';
import heroBackground from '../assets/pexels-jan-van-der-wolf-11680885-32239084.jpg';

const Header = () => {
  return (
    <header
      id="home"
      className="header"
      style={{ '--hero-image': `url(${heroBackground})` }}
    >
      <div className="container hero-content">
        <div className="brand-lockup">
          <span className="eyebrow">Civil / Project Engineer</span>
          <h1>John Doe</h1>
          <p>Infrastructure delivery, site coordination, and technical project controls.</p>
        </div>
      </div>
    </header>
  );
};

export default Header;
